<div class="wrap" id="wrap">
  <div class="bar" id="bar">
    <span class="crest"><svg viewBox="0 0 24 24"><rect x="4" y="3" width="16" height="18" rx="2"/><circle cx="12" cy="9" r="2.5"/><path d="M8 17a4 4 0 0 1 8 0"/></svg></span>
    <span class="bar-id"><span class="ttl" id="ttl">ADVENTURER CARD</span><span class="nm" id="nm"></span></span>
    <span class="lvpill"><span class="lv" id="lvNum">1</span><span class="lvl" id="lvLbl">Level</span></span>
    <span class="chev"><svg viewBox="0 0 24 24"><polyline points="6 9 12 15 18 9"/></svg></span>
  </div>
  <div class="strip">
    <div class="xp-top"><span class="xp-l"><svg viewBox="0 0 24 24"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg><span id="xpL">Experience</span></span><span class="xp-v" id="xpV"></span></div>
    <div class="xp-bar"><div class="xp-fill" id="xpFill"></div></div>
    <div class="spline">
      <div class="spbox"><svg viewBox="0 0 24 24"><path d="M12 2l2.5 5 5.5.8-4 3.9 1 5.5-5-2.6-5 2.6 1-5.5-4-3.9 5.5-.8z"/></svg><span class="spi"><span class="spn" id="spNum">0</span><span class="spl" id="spLbl">Skill Points</span></span></div>
      <div class="rankpill"><span class="rv" id="rankV">Beginner</span><span class="rl" id="rankL">Rank</span></div>
    </div>
  </div>
  <div class="body" id="body">
    <div class="seg">
      <div class="tab on" data-p="pProf"><svg viewBox="0 0 24 24"><circle cx="12" cy="8" r="4"/><path d="M4 21a8 8 0 0 1 16 0"/></svg><span id="lP">Profile</span></div>
      <div class="tab" data-p="pAttr"><svg viewBox="0 0 24 24"><line x1="4" y1="21" x2="4" y2="13"/><line x1="4" y1="9" x2="4" y2="3"/><line x1="12" y1="21" x2="12" y2="12"/><line x1="12" y1="8" x2="12" y2="3"/><line x1="20" y1="21" x2="20" y2="15"/><line x1="20" y1="11" x2="20" y2="3"/><line x1="1" y1="13" x2="7" y2="13"/><line x1="9" y1="8" x2="15" y2="8"/><line x1="17" y1="15" x2="23" y2="15"/></svg><span id="lA">Stats</span></div>
      <div class="tab" data-p="pSkill"><svg viewBox="0 0 24 24"><path d="M12 2l2.5 5 5.5.8-4 3.9 1 5.5-5-2.6-5 2.6 1-5.5-4-3.9 5.5-.8z"/></svg><span id="lS">Skills</span></div>
      <div class="tab" data-p="pVit"><svg viewBox="0 0 24 24"><path d="M12 21C7 17 3 13 3 8.5A4.5 4.5 0 0 1 12 6a4.5 4.5 0 0 1 9 2.5C21 13 17 17 12 21z"/></svg><span id="lV">Vitals</span></div>
      <div class="tab" data-p="pParty"><svg viewBox="0 0 24 24"><circle cx="9" cy="8" r="3.2"/><path d="M3 20a6 6 0 0 1 12 0"/><circle cx="17" cy="9" r="2.6"/><path d="M15.5 14.5A5 5 0 0 1 21 19"/></svg><span id="lT">Party</span></div>
      <div class="tab" data-p="pIntim"><svg viewBox="0 0 24 24"><path d="M12 21C7 17 3 13 3 8.5A4.5 4.5 0 0 1 12 6a4.5 4.5 0 0 1 9 2.5C21 13 17 17 12 21z"/></svg><span id="lI">Intimacy</span></div>
      <div class="tab" data-p="pQuest"><svg viewBox="0 0 24 24"><path d="M9 5H7a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2h-2"/><rect x="9" y="3" width="6" height="4" rx="1"/><path d="M9 13l2 2 4-4"/></svg><span id="lQ">Quests</span></div>
    </div>
    <div class="pane on" id="pProf"></div>
    <div class="pane" id="pAttr"></div>
    <div class="pane" id="pSkill"></div>
    <div class="pane" id="pVit"></div>
    <div class="pane" id="pParty"></div>
    <div class="pane" id="pIntim"></div>
    <div class="pane" id="pQuest"></div>
    <div class="tree" id="tree"></div>
  </div>
</div>
<script>
(function(){
  function g(id){return document.getElementById(id);}
  var raw=(g('raw').value||'').replace(/<\/?KS_STATUS>/gi,'').trim();
  var D={}; try{ if(raw && raw.charAt(0)==='{') D=JSON.parse(raw);}catch(e){}
  var th=(D.ui_lang==='th');
  if(D.ui_theme==='light') document.documentElement.classList.add('lt');

  function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
  function val(v){ if(v==null) return ''; if(Array.isArray(v)) return v.filter(function(x){return x!=null&&String(x).trim()!=='';}); return String(v).trim(); }
  function num(v){ var n=parseInt(v,10); return isNaN(n)?0:n; }
  function fmt(n){ return String(n).replace(/\B(?=(\d{3})+(?!\d))/g,','); }
  function T(en,t){ return th?t:en; }

  g('ttl').textContent= T('ADVENTURER CARD','การ์ดนักผจญภัย');
  g('nm').textContent= (val(D.name)||T('Unregistered','ยังไม่ลงทะเบียน')) + (val(D.class_label)?(' · '+val(D.class_label)):'');
  g('lvNum').textContent= num(D.level)||1;
  g('lvLbl').textContent= T('Level','เลเวล');

  /* ---- EXP ---- */
  var ex=D.exp||{}; var ec=num(ex.cur), em=num(ex.max)||100; var epct=em>0?Math.max(0,Math.min(100,Math.round(ec/em*100))):0;
  g('xpL').textContent= T('Experience','ค่าประสบการณ์');
  g('xpV').textContent= fmt(ec)+' / '+fmt(em)+' EXP';
  g('xpFill').style.width=epct+'%';

  /* ---- Skill points + rank ---- */
  g('spNum').textContent= num(D.skill_points);
  g('spLbl').textContent= T('Skill Points available','พ้อยสกิลที่ใช้ได้');
  var lv=num(D.level)||1;
  var rank=val(D.rank)|| (lv>30?T('Advanced','ขั้นสูง'):(lv>=20?T('Intermediate','ขั้นกลาง'):T('Beginner','มือใหม่')));
  g('rankV').textContent=rank;
  g('rankL').textContent=T('Rank','อันดับ');

  /* ---- tabs labels ---- */
  g('lP').textContent=T('Profile','โปรไฟล์');
  g('lA').textContent=T('Stats','ค่าสถานะ');
  g('lS').textContent=T('Skills','สกิล');
  g('lV').textContent=T('Vitals','พลังชีวิต');
  g('lT').textContent=T('Party','ปาร์ตี้');
  g('lI').textContent=T('Intimacy','ความใกล้ชิด');
  g('lQ').textContent=T('Quests','เควส');

  /* ---- PROFILE ---- */
  var IC={
    name:'<circle cx="12" cy="8" r="4"/><path d="M4 21a8 8 0 0 1 16 0"/>',
    age:'<circle cx="12" cy="12" r="9"/><polyline points="12 7 12 12 16 14"/>',
    gender:'<circle cx="12" cy="10" r="5"/><line x1="12" y1="15" x2="12" y2="22"/><line x1="9" y1="19" x2="15" y2="19"/>',
    race:'<path d="M12 2l2.5 5 5.5.8-4 3.9 1 5.5-5-2.6-5 2.6 1-5.5-4-3.9 5.5-.8z"/>',
    job:'<rect x="3" y="7" width="18" height="13" rx="1"/><path d="M8 7V5a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/>',
    rank:'<polyline points="6 14 12 8 18 14"/><polyline points="6 18 12 12 18 18"/>',
    homeland:'<path d="M3 11l9-7 9 7"/><path d="M5 10v10h14V10"/><path d="M10 20v-6h4v6"/>',
    faction:'<path d="M4 21V4l9 2v13"/><path d="M13 6l7 1.5V17l-7-1.5"/>',
    reputation:'<polygon points="12 3 14.6 8.6 21 9.3 16.5 13.7 17.8 20 12 16.8 6.2 20 7.5 13.7 3 9.3 9.4 8.6"/>',
    goal:'<circle cx="12" cy="12" r="9"/><circle cx="12" cy="12" r="4"/><circle cx="12" cy="12" r="0.6"/>'
  };
  var LB={name:['Name','ชื่อ'],class_label:['Class / Job','คลาส / อาชีพ'],age:['Age','อายุ'],gender:['Gender','เพศ'],race:['Race','เผ่าพันธุ์'],homeland:['Homeland','ถิ่นกำเนิด'],faction:['Affiliation','สังกัด'],reputation:['Reputation','ชื่อเสียง'],goal:['Goal','เป้าหมาย']};
  var order=['name','class_label','race','gender','age','homeland','faction','reputation','goal'];
  var ICK={name:'name',class_label:'job',race:'race',gender:'gender',age:'age',homeland:'homeland',faction:'faction',reputation:'reputation',goal:'goal'};
  var wide={name:1,goal:1,reputation:1};

  var pro='';
  /* wallet */
  var cur=D.currency||{}; var eris=val(cur.eris)||val(D.eris);
  var debt=val(D.debt);
  if(eris||debt){
    pro+='<div class="wallet">';
    if(eris!=='') pro+='<div class="coin"><svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="9"/><path d="M15 9.5a3 3 0 0 0-3-1.5c-2 0-3 1-3 4s1 4 3 4a3 3 0 0 0 3-1.5"/></svg><span class="coin-i"><span class="coin-n">'+esc(fmt(num(eris)))+'</span><span class="coin-l">'+T('Eris','อีริส')+'</span></span></div>';
    if(debt!=='' && num(debt)>0) pro+='<div class="coin debt"><svg viewBox="0 0 24 24"><path d="M12 2v20"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg><span class="coin-i"><span class="coin-n">'+esc(fmt(num(debt)))+'</span><span class="coin-l">'+T('Debt','หนี้สิน')+'</span></span></div>';
    pro+='</div>';
  }
  var present=order.filter(function(k){ return val(D[k]); });
  var halves=present.filter(function(k){return !wide[k];});
  var promote=(halves.length%2===1)?halves[halves.length-1]:null;
  var grid='';
  present.forEach(function(k){
    var full=wide[k]||k===promote;
    grid+='<div class="info'+(full?' full':'')+'"><span class="info-ic"><svg viewBox="0 0 24 24">'+IC[ICK[k]]+'</svg></span><span class="info-b"><span class="info-l">'+esc(LB[k][th?1:0])+'</span><span class="info-v">'+esc(val(D[k]))+'</span></span></div>';
  });
  if(grid) pro+='<div class="grid">'+grid+'</div>';
  if(!pro) pro='<div class="empty">'+T('No data yet','ยังไม่มีข้อมูล')+'</div>';
  g('pProf').innerHTML=pro;

  /* ---- ATTRIBUTES ---- */
  var ATD={
    str:['Strength','STR','พละกำลัง','Physical power and toughness.','พละกำลังและความทนทาน'],
    vit:['Vitality','VIT','พลังชีวิต','Health, endurance, the size of your HP.','สุขภาพและความอึด'],
    agi:['Agility','AGI','ความว่องไว','Speed, reflex, balance.','ความเร็วและการทรงตัว'],
    dex:['Dexterity','DEX','ความแม่นยำ','Accuracy with weapons and tools.','ความแม่นยำในการใช้อาวุธ'],
    int:['Intelligence','INT','สติปัญญา','Knowledge; gates magic casting.','ความรู้ ใช้ร่ายเวท'],
    mgc:['Magic Power','MGC','พลังเวท','The size of your mana well (MP).','ขนาดบ่อมานา'],
    luk:['Luck','LUK','โชค','Fortune — Steal, Snipe, Bind, gambling.','โชค — ขโมย ซุ่มยิง มัด พนัน']
  };
  var ICA={str:'<path d="M6 13a4 4 0 1 1 4-4"/><path d="M14 11a4 4 0 1 0 4 4"/><line x1="9" y1="9" x2="15" y2="15"/>',
    vit:'<path d="M12 21C7 17 3 13 3 8.5A4.5 4.5 0 0 1 12 6a4.5 4.5 0 0 1 9 2.5C21 13 17 17 12 21z"/>',
    agi:'<path d="M13 2L4.5 13.5H11l-1 8.5L19.5 10H13z"/>',
    dex:'<circle cx="12" cy="12" r="9"/><circle cx="12" cy="12" r="4"/><circle cx="12" cy="12" r="0.5"/>',
    int:'<path d="M9 18h6"/><path d="M10 22h4"/><path d="M12 2a7 7 0 0 0-4 12.7V17h8v-2.3A7 7 0 0 0 12 2z"/>',
    mgc:'<path d="M12 3C9 8 6 11 6 15a6 6 0 0 0 12 0c0-4-3-7-6-12z"/>',
    luk:'<path d="M12 21c-1-5-5-6-5-10a5 5 0 0 1 10 0c0 4-4 5-5 10z"/><circle cx="12" cy="11" r="1.4"/>'};
  var aorder=['str','vit','agi','dex','int','mgc','luk'];
  var attrs=D.attributes||{};
  var ah='';
  aorder.forEach(function(k){
    if(attrs[k]==null) return;
    var v=Math.max(0,Math.min(10,num(attrs[k])));
    var segs='';
    for(var i=1;i<=10;i++){ segs+='<div class="at-tk'+(i<=v?' on':'')+(i>=9&&i<=v?' hi':'')+'"></div>'; }
    ah+='<div class="at-wrap"><div class="at-top"><span class="at-n"><svg viewBox="0 0 24 24" fill="none">'+ICA[k]+'</svg>'+esc(T(ATD[k][0],ATD[k][2]))+'</span><span class="at-v">'+v+'<span class="of">/10</span></span></div><div class="at-d">'+esc(T(ATD[k][3],ATD[k][4]))+'</div><div class="at-bar">'+segs+'</div></div>';
  });
  g('pAttr').innerHTML= ah||'<div class="empty">'+T('No attributes recorded','ยังไม่มีค่าสถานะ')+'</div>';

  /* ---- SKILLS ---- */
  var sk='';
  sk+='<div class="sp-hd"><svg viewBox="0 0 24 24"><path d="M12 2l2.5 5 5.5.8-4 3.9 1 5.5-5-2.6-5 2.6 1-5.5-4-3.9 5.5-.8z"/></svg><div class="spi"><div class="spn">'+num(D.skill_points)+'</div><div class="spl">'+T('Skill Points to spend','พ้อยสกิลที่ใช้ได้')+'</div></div><div class="sphint">'+T('+1 SP per level-up. Spend on skills taught by someone who knows them.','+1 พ้อยต่อการเลเวลอัพ ใช้เรียนสกิลจากผู้ที่สอนได้')+'</div></div>';
  var skills=Array.isArray(D.skills)?D.skills:[];
  if(skills.length){
    var groups={}; var gorder=[];
    skills.forEach(function(s){ var c=val(s.cat)||T('General','ทั่วไป'); if(!groups[c]){groups[c]=[];gorder.push(c);} groups[c].push(s); });
    gorder.forEach(function(c){
      sk+='<div class="skcat">'+esc(c)+'</div>';
      groups[c].forEach(function(s){
        sk+='<div class="sk"><div class="sk-top"><span class="sk-n">'+esc(val(s.n)||'—')+'</span>'+(val(s.cost)!==''?'<span class="sk-cost">'+esc(val(s.cost))+' SP</span>':'')+'</div>'+(val(s.d)?'<div class="sk-d">'+esc(s.d)+'</div>':'')+'</div>';
      });
    });
  } else {
    sk+='<div class="empty">'+T('No skills learned yet','ยังไม่ได้เรียนสกิล')+'</div>';
  }
  g('pSkill').innerHTML=sk;

  /* ---- VITALS ---- */
  function bar(obj,cls,label,icon,col,note){
    if(!obj) return '';
    var c=num(obj.cur), m=num(obj.max)||100; var pct=m>0?Math.max(0,Math.min(100,Math.round(c/m*100))):0; var dep=c<=0;
    var h='<div class="vit"><div class="vtop"><div class="vn">'+icon+esc(label)+'</div><div class="vv" style="color:'+col+'">'+fmt(c)+' / '+fmt(m)+'<span class="vpct">'+pct+'%</span></div></div>';
    h+='<div class="vbar"><div class="vfill '+cls+(dep?' dep':'')+'" style="width:'+(dep?100:pct)+'%"></div></div>';
    if(dep) h+='<div class="vnote"><svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12" y2="16"/></svg>'+esc(note)+'</div>';
    return h+'</div>';
  }
  var hpI='<svg viewBox="0 0 24 24" stroke="#5fc27e"><path d="M12 21C7 17 3 13 3 8.5A4.5 4.5 0 0 1 12 6a4.5 4.5 0 0 1 9 2.5C21 13 17 17 12 21z"/></svg>';
  var mpI='<svg viewBox="0 0 24 24" stroke="#5aa2e6"><path d="M12 3C9 8 6 11 6 15a6 6 0 0 0 12 0c0-4-3-7-6-12z"/></svg>';
  var vh='';
  vh+=bar(D.hp,'hp',T('Health (HP)','พลังชีวิต (HP)'),hpI,'#5fc27e',T('Down — you collapse, needing healing or revival','หมดแรง — ล้มลง ต้องรักษาหรือชุบชีวิต'));
  vh+=bar(D.mp,'mp',T('Mana (MP)','มานา (MP)'),mpI,'#5aa2e6',T('Empty — casting now drains your HP instead','มานาหมด — ร่ายเวทจะดูด HP แทน'));
  g('pVit').innerHTML= vh||'<div class="empty">'+T('No data yet','ยังไม่มีข้อมูล')+'</div>';

  /* ---- PARTY ---- */
  var party=Array.isArray(D.party)?D.party:[];
  var pcols=['#4fd6e6','#e2b341','#a98bf0','#5fc27e','#e0625a','#5aa2e6'];
  if(party.length){
    var ph='';
    party.forEach(function(p,i){
      var nm=val(p.n)||'—'; var ini=nm.charAt(0).toUpperCase(); var col=pcols[i%pcols.length];
      ph+='<div class="pm"><div class="pm-av" style="background:'+col+'">'+esc(ini)+'</div><div class="pm-i"><div class="pm-top"><span class="pm-n">'+esc(nm)+'</span>'+(val(p.class)?'<span class="pm-c">'+esc(p.class)+'</span>':'')+'</div>'+(val(p.d)?'<div class="pm-d">'+esc(p.d)+'</div>':'')+'</div></div>';
    });
    g('pParty').innerHTML=ph;
  } else { g('pParty').innerHTML='<div class="empty">'+T('Adventuring solo','ผจญภัยคนเดียว')+'</div>'; }

  /* ---- INTIMACY (18+) ---- */
  var heartI='<svg viewBox="0 0 24 24"><path d="M12 21C7 17 3 13 3 8.5A4.5 4.5 0 0 1 12 6a4.5 4.5 0 0 1 9 2.5C21 13 17 17 12 21z"/></svg>';
  var im=Array.isArray(D.intimacy)?D.intimacy:[];
  if(im.length){
    var ih='<div class="im-note">'+T('All partners are adults (18+). Consent &amp; limits always apply.','คู่สัมพันธ์ทุกคนเป็นผู้ใหญ่ (18+) ยึดการยินยอมและขอบเขตเสมอ')+'</div>';
    im.forEach(function(p,i){
      var nm=val(p.n)||'—'; var ini=nm.charAt(0).toUpperCase(); var col=pcols[i%pcols.length];
      ih+='<div class="im"><div class="im-top"><div class="im-av" style="background:'+col+'">'+esc(ini)+'</div><div class="im-id"><div class="im-n">'+esc(nm)+'</div></div>'+(val(p.stage)?'<div class="im-stage">'+esc(p.stage)+'</div>':'')+'</div>';
      var aff=p.affection||{};
      if(aff.cur!=null||aff.max!=null){ var ac=num(aff.cur), am=num(aff.max)||100; var apct=am>0?Math.max(0,Math.min(100,Math.round(ac/am*100))):0;
        ih+='<div class="im-aff"><div class="im-afftop"><span>'+T('Affection','ความรักใคร่')+'</span><span class="av">'+ac+' / '+am+'</span></div><div class="im-bar"><div class="im-fill" style="width:'+apct+'%"></div></div></div>'; }
      if(val(p.level)) ih+='<div class="im-lvl">'+heartI+T('Intimacy','ความใกล้ชิด')+': '+esc(p.level)+'</div>';
      var likes=val(p.likes); if(Array.isArray(likes)&&likes.length){ ih+='<div class="im-sec"><div class="im-lbl">'+T('Likes / Kinks','ชอบ / รสนิยม')+'</div><div class="im-chips">'+likes.map(function(x){return '<span class="im-chip like">'+esc(x)+'</span>';}).join('')+'</div></div>'; }
      var lims=val(p.limits); if(Array.isArray(lims)&&lims.length){ ih+='<div class="im-sec"><div class="im-lbl">'+T('Limits','ขอบเขต / ไม่เอา')+'</div><div class="im-chips">'+lims.map(function(x){return '<span class="im-chip lim">'+esc(x)+'</span>';}).join('')+'</div></div>'; }
      if(val(p.notes)) ih+='<div class="im-notes">'+esc(p.notes)+'</div>';
      if(val(p.history)) ih+='<div class="im-hist">'+esc(p.history)+'</div>';
      ih+='</div>';
    });
    g('pIntim').innerHTML=ih;
  } else { g('pIntim').innerHTML='<div class="empty">'+T('No intimate bonds yet','ยังไม่มีความสัมพันธ์ใกล้ชิด')+'</div>'; }

  /* ---- QUESTS ---- */
  var QS={ongoing:['Ongoing','กำลังทำ'],success:['Complete','สำเร็จ'],failed:['Failed','ล้มเหลว']};
  var qarr=Array.isArray(D.quests)?D.quests:(D.quest?[D.quest]:[]);
  if(qarr.length){
    var qh='';
    qarr.forEach(function(qq){
      var stt=(val(qq.status)||'ongoing').toLowerCase(); if(!QS[stt]) stt='ongoing';
      qh+='<div class="q"><div class="qtop"><div class="qn">'+esc(val(qq.name)||T('Quest','เควส'))+'</div>';
      if(val(qq.rank)) qh+='<div class="qrank">'+esc(qq.rank)+'</div>';
      qh+='<div class="qst '+stt+'">'+esc(QS[stt][th?1:0])+'</div></div>';
      if(val(qq.objective)) qh+='<div class="qobj"><span class="ql">'+T('Objective','เป้าหมาย')+'</span><span>'+esc(qq.objective)+'</span></div>';
      if(val(qq.info)) qh+='<div class="qinfo">'+esc(qq.info)+'</div>';
      qh+='</div>';
    });
    g('pQuest').innerHTML=qh;
